() => {
    const table = document.querySelector('table[aria-label="Bin collection dates"]');
    const rows = Array.from(table.querySelectorAll('tbody tr'));
    const data = {};

    rows.forEach(row => {
        const date = row.querySelector('td:nth-child(1)').innerText;
        const blackBin = row.querySelector('td:nth-child(2)').innerText;
        const blueBin = row.querySelector('td:nth-child(3)').innerText;
        const greenBin = row.querySelector('td:nth-child(4)').innerText;

        if (blackBin.trim() !== '') {
            data.blackBin = { next_pickup_day: date, frequency: 'Every two weeks' };
        }
        if (blueBin.trim() !== '') {
            data.blueBin = { next_pickup_day: date, frequency: 'Every two weeks' };
        }
        if (greenBin.trim() !== '') {
            data.greenBin = { next_pickup_day: date, frequency: 'Every two weeks' };
        }
    });
    return data;
}

